Greedy insertion with cheapest feasible assign selection and empty assign fallback, evaluating each candidate via temporary trial and rollback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := 0; shipIdx < len(oris); shipIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 1e100
		ori := oris[shipIdx]
		des := dess[shipIdx]
		shipID := total_ship + shipIdx

		for ai := 0; ai < dispatch.AssignsLen; ai++ {
			oldCost := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				newCost := dispatch.Assigns[ai].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestCostDelta {
						bestCostDelta = delta
						bestAssignIdx = ai
					}
				}
				dispatch.Assigns[ai].RemoveShip(shipID)
				dispatch.Assigns[ai].GenRoute()
			}
		}

		targetAssignIdx := bestAssignIdx
		if targetAssignIdx == -1 {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetAssignIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			} else {
				targetAssignIdx = dispatch.AssignsLen - 1
			}
		}

		added := dispatch.Assigns[targetAssignIdx].AddShip(shipID, ori, des)
		if added {
			dispatch.Assigns[targetAssignIdx].GenRoute()
		} else if dispatch.AssignsLen < MAXASSIGNS {
			fallbackIdx := dispatch.AssignsLen
			dispatch.AssignsLen++
			dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[fallbackIdx].GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

